#include <oesdk/syscall.h>
int64_t OesdkSystemCallDispatch(const OesdkSystemCallTable*T,const OesdkAddressSpace*A,const OesdkSystemCallArguments*X){OesdkSystemCallHandler H;bool Write=false;if(T==NULL||A==NULL||X==NULL)return OESDK_STATUS_INVALID_ARGUMENT;if(X->Number>OesdkSystemCallEvent)return OESDK_STATUS_NOT_SUPPORTED;H=X->Number==OesdkSystemCallGet?T->Get:(X->Number==OesdkSystemCallSet?T->Set:T->Event);Write=X->Number==OesdkSystemCallGet;if(H==NULL)return OESDK_STATUS_NOT_SUPPORTED;if(X->BufferLength>0U&&!OesdkUserRangeValidate(A,X->Buffer,X->BufferLength,Write))return OESDK_STATUS_INVALID_ARGUMENT;return H(X,T->Context);}
